describe("Constructor",()=>{describe("Temporal.ZonedDateTime()",()=>{it("Using Temporal.ZonedDateTime()",()=>{let e=new Temporal.ZonedDateTime(0n,"America/New_York");expect(e.toString()).toBe("1969-12-31T19:00:00-05:00[America/New_York]")})})});describe("Static methods",()=>{describe("Temporal.ZonedDateTime.compare()",()=>{it("Using Temporal.ZonedDateTime.compare()",()=>{let e=Temporal.ZonedDateTime.from("2021-08-01T01:00:00[Europe/London]"),o=Temporal.ZonedDateTime.from("2021-08-02T00:00:00[Europe/London]");expect(Temporal.ZonedDateTime.compare(e,o)).toBe(-1);let t=Temporal.ZonedDateTime.from("2021-08-01T00:00:00[Europe/London]");expect(Temporal.ZonedDateTime.compare(e,t)).toBe(1)}),it("Sorting an array of date-times #1",()=>{let e=[Temporal.ZonedDateTime.from("2021-08-01T00:00:00[America/New_York]"),Temporal.ZonedDateTime.from("2021-08-01T00:00:00[Asia/Hong_Kong]"),Temporal.ZonedDateTime.from("2021-08-01T00:00:00[Europe/London]")];e.sort(Temporal.ZonedDateTime.compare),expect(e.map(o=>o.toString())).toStrictEqual(["2021-08-01T00:00:00+08:00[Asia/Hong_Kong]","2021-08-01T00:00:00+01:00[Europe/London]","2021-08-01T00:00:00-04:00[America/New_York]"])}),it("Sorting an array of date-times #2",()=>{let e=[Temporal.ZonedDateTime.from("2021-08-01T00:00:00[America/New_York]"),Temporal.ZonedDateTime.from("2021-08-01T00:00:00[Asia/Hong_Kong]"),Temporal.ZonedDateTime.from("2021-08-01T00:00:00[Europe/London]")];e.sort((o,t)=>Temporal.PlainDateTime.compare(o.toPlainDateTime(),t.toPlainDateTime())),expect(e.map(o=>o.toString())).toStrictEqual(["2021-08-01T00:00:00-04:00[America/New_York]","2021-08-01T00:00:00+08:00[Asia/Hong_Kong]","2021-08-01T00:00:00+01:00[Europe/London]"])})}),describe("Temporal.ZonedDateTime.from()",()=>{it("Creating a ZonedDateTime from an object",()=>{let e=Temporal.ZonedDateTime.from({timeZone:"America/New_York",year:2021,month:7,day:1,hour:12,minute:34,second:56});expect(e.toString()).toBe("2021-07-01T12:34:56-04:00[America/New_York]")}),it("Creating a ZonedDateTime from a string",()=>{let e=Temporal.ZonedDateTime.from("2021-07-01T12:34:56Z[America/New_York]");expect(e.toString()).toBe("2021-07-01T08:34:56-04:00[America/New_York]")}),it("Creating a ZonedDateTime from an ISO 8601 / RFC 3339 string",()=>{let t=Temporal.Instant.from("2021-07-01T12:34:56+02:00").toZonedDateTimeISO("America/New_York");expect(t.toString()).toBe("2021-07-01T06:34:56-04:00[America/New_York]")}),it("Local time disambiguation",()=>{let o=Temporal.ZonedDateTime.from("2024-03-10T02:05:00[America/New_York]");expect(o.toString()).toBe("2024-03-10T03:05:00-04:00[America/New_York]");let n=Temporal.ZonedDateTime.from("2024-11-03T01:05:00[America/New_York]");expect(n.toString()).toBe("2024-11-03T01:05:00-04:00[America/New_York]")})})});describe("Temporal.ZonedDateTime",()=>{describe("creation and parsing",()=>{it("can be created from an RFC 9557 string",()=>{let e=Temporal.ZonedDateTime.from("2021-08-19T17:01:00+01:00[Europe/London]");expect(e.toString()).toContain("2021-08-19T17:01:00+01:00[Europe/London]")}),it("can be created from an own object",()=>{let e=Temporal.ZonedDateTime.from("2021-08-19T17:01:00+01:00[Europe/London]"),o=Temporal.ZonedDateTime.from(e);expect(e).toEqual(o)}),it("can be created from an object containing properties",()=>{let e=Temporal.ZonedDateTime.from({timeZone:"America/Los_Angeles",year:1995,month:12,day:7,hour:3,minute:24,second:30,millisecond:0,microsecond:3,nanosecond:500});expect(e.toString()).toEqual("1995-12-07T03:24:30.0000035-08:00[America/Los_Angeles]")})}),describe("arithmetic methods",()=>{let e=Temporal.ZonedDateTime.from("2020-01-01T12:00:00+00:00[UTC]"),o=Temporal.ZonedDateTime.from("2020-01-02T12:00:00+00:00[UTC]");it("add() advances the date/time",()=>{let t=e.add({days:1});expect(t.day).toBe(2)}),it("compare() method works for two ZonedDateTime objects",()=>{expect(Temporal.ZonedDateTime.compare(e,o)).toBe(-1),expect(Temporal.ZonedDateTime.compare(o,e)).toBe(1),expect(Temporal.ZonedDateTime.compare(e,e)).toBe(0)}),it("equals() verifies if two ZonedDateTime are equal",()=>{let t=Temporal.ZonedDateTime.from("2020-01-01T12:00:00[UTC]");expect(e.equals(t)).toBe(!0)}),it("getTimeZoneTransition() returns the next and previous timezone offset transitions",()=>{let t=Temporal.ZonedDateTime.from("2024-01-01T00-05:00[America/New_York]"),n=t.getTimeZoneTransition("next");expect(n.toString()).toBe("2024-03-10T03:00:00-04:00[America/New_York]");let a=n.getTimeZoneTransition("next");expect(a.toString()).toBe("2024-11-03T01:00:00-05:00[America/New_York]");let r=t.getTimeZoneTransition("previous");expect(r.toString()).toBe("2023-11-05T01:00:00-05:00[America/New_York]");let i=Temporal.ZonedDateTime.from("2024-01-01T00Z[UTC]");expect(i.getTimeZoneTransition("next")).toBe(null)}),it("round() supports various forms, roundingMode, and roundingIncrement",()=>{let t=e.add({milliseconds:500}),n=t.round({smallestUnit:"second"});expect(n.second).toBe(1),expect(n.offset).toBe("+00:00"),expect(n.timeZoneId).toBe("UTC");let a=t.round({smallestUnit:"second",roundingMode:"trunc"});expect(a.second).toBe(0);let r=e.add({minutes:7,seconds:15}),i=r.round("minute");expect(i.minute).toBe(7),expect(i.second).toBe(0);let c=r.round({smallestUnit:"minute",roundingIncrement:15});expect(c.minute).toBe(0);let m=r.round({smallestUnit:"hour",roundingIncrement:2});expect(m.hour).toBe(12)}),it("since() returns correct duration",()=>{let t=o.since(e);expect(t.sign).toBe(1),expect(t.years).toBe(0),expect(t.months).toBe(0),expect(t.days).toBe(0),expect(t.hours).toBe(24),expect(t.minutes).toBe(0),expect(t.seconds).toBe(0),expect(t.milliseconds).toBe(0),expect(t.microseconds).toBe(0),expect(t.nanoseconds).toBe(0)}),it("subtract() decrements by a duration",()=>{let t=e.subtract({hours:1});expect(t.hour).toBeLessThan(e.hour)}),it("toInstant() returns a Temporal.Instant",()=>{let t=e.toInstant();expect(t).toBeInstanceOf(Temporal.Instant)}),it("toPlainDate() returns a Temporal.PlainDate",()=>{let t=e.toPlainDate();expect(t).toBeInstanceOf(Temporal.PlainDate),expect(t.toString()).toBe("2020-01-01")}),it("toPlainDateTime() returns a Temporal.PlainDateTime",()=>{let t=e.toPlainDateTime();expect(t).toBeInstanceOf(Temporal.PlainDateTime),expect(t.toString()).toBe("2020-01-01T12:00:00")}),it("toPlainTime() returns a Temporal.PlainTime",()=>{let t=e.toPlainTime();expect(t).toBeInstanceOf(Temporal.PlainTime),expect(t.toString()).toBe("12:00:00")}),it("toString() returns an ISO string representation",()=>{let t=e.toString();expect(typeof t).toBe("string"),expect(t).toBe("2020-01-01T12:00:00+00:00[UTC]")}),it("until() returns correct duration",()=>{let t=e.until(o);expect(t.sign).toBe(1),expect(t.years).toBe(0),expect(t.months).toBe(0),expect(t.days).toBe(0),expect(t.hours).toBe(24),expect(t.minutes).toBe(0),expect(t.seconds).toBe(0),expect(t.milliseconds).toBe(0),expect(t.microseconds).toBe(0),expect(t.nanoseconds).toBe(0)}),it("valueOf() throws a TypeError",()=>{expect(()=>{+e}).toThrow()}),it("with() method returns a new ZonedDateTime with updated fields",()=>{let t=e.with({day:15});expect(t.day).toBe(15),expect(t.month).toBe(e.month)}),it("withTimeZone() method returns a new ZonedDateTime with replaceing timezone",()=>{let t=e.withTimeZone("Asia/Tokyo");expect(t.toString()).toBe("2020-01-01T21:00:00+09:00[Asia/Tokyo]")})}),describe("properties",()=>{let e=Temporal.ZonedDateTime.from("2020-01-01T12:00:00[UTC]");it("should have correct date and time properties",()=>{expect(e.year).toBe(2020),expect(e.month).toBe(1),expect(e.day).toBe(1),expect(e.hour).toBe(12),expect(e.minute).toBe(0),expect(e.second).toBe(0),expect(e.millisecond).toBe(0),expect(e.offset).toBe("+00:00"),expect(typeof e.epochMilliseconds).toBe("number"),expect(e.epochMilliseconds).toBeGreaterThan(0),expect(typeof e.epochNanoseconds).toBe("bigint"),expect(e.epochNanoseconds).toBeGreaterThan(0n),expect(e.dayOfYear).toBe(1),expect(e.daysInMonth).toBe(31),expect(e.daysInYear).toBe(366),expect(e.inLeapYear).toBe(!0)}),it("has correct toStringTag",()=>{expect(Object.prototype.toString.call(e)).toBe("[object Temporal.ZonedDateTime]")})})});
